class WaveTexture(NodeBuilder):
    """
    Generate procedural bands or rings with noise

    Parameters
    ----------
    vector : InputVector
        Vector
    scale : InputFloat
        Scale
    distortion : InputFloat
        Distortion
    detail : InputFloat
        Detail
    detail_scale : InputFloat
        Detail Scale
    detail_roughness : InputFloat
        Detail Roughness
    phase_offset : InputFloat
        Phase Offset

    Outputs
    -------
    color : ColorSocket
        Color
    fac : FloatSocket
        Factor
    """

    _bl_idname = "ShaderNodeTexWave"
    node: bpy.types.ShaderNodeTexWave

    class Inputs(SocketAccessor):
        vector: Socket
        scale: Socket
        distortion: Socket
        detail: Socket
        detail_scale: Socket
        detail_roughness: Socket
        phase_offset: Socket

    class Outputs(SocketAccessor):
        color: ColorSocket
        fac: FloatSocket

    @property
    def i(self) -> "WaveTexture.Inputs":
        return WaveTexture.Inputs(self.node.inputs, "input")

    @property
    def o(self) -> "WaveTexture.Outputs":
        return WaveTexture.Outputs(self.node.outputs, "output")

    def __init__(
        self,
        vector: InputVector = None,
        scale: InputFloat = 5.0,
        distortion: InputFloat = 0.0,
        detail: InputFloat = 2.0,
        detail_scale: InputFloat = 1.0,
        detail_roughness: InputFloat = 0.5,
        phase_offset: InputFloat = 0.0,
        *,
        wave_type: Literal["BANDS", "RINGS"] = "BANDS",
        bands_direction: Literal["X", "Y", "Z", "DIAGONAL"] = "X",
        rings_direction: Literal["X", "Y", "Z", "SPHERICAL"] = "X",
        wave_profile: Literal["SIN", "SAW", "TRI"] = "SIN",
    ):
        super().__init__()
        key_args = {
            "Vector": vector,
            "Scale": scale,
            "Distortion": distortion,
            "Detail": detail,
            "Detail Scale": detail_scale,
            "Detail Roughness": detail_roughness,
            "Phase Offset": phase_offset,
        }
        self.wave_type = wave_type
        self.bands_direction = bands_direction
        self.rings_direction = rings_direction
        self.wave_profile = wave_profile
        self._establish_links(**key_args)

    @classmethod
    def bands(
        cls,
        vector: InputVector = None,
        scale: InputFloat = 5.0,
        distortion: InputFloat = 0.0,
        detail: InputFloat = 2.0,
        detail_scale: InputFloat = 1.0,
        detail_roughness: InputFloat = 0.5,
        phase_offset: InputFloat = 0.0,
    ) -> "WaveTexture":
        """Create Wave Texture with operation 'Bands'. Use standard wave texture in bands"""
        return cls(
            wave_type="BANDS",
            vector=vector,
            scale=scale,
            distortion=distortion,
            detail=detail,
            detail_scale=detail_scale,
            detail_roughness=detail_roughness,
            phase_offset=phase_offset,
        )

    @classmethod
    def rings(
        cls,
        vector: InputVector = None,
        scale: InputFloat = 5.0,
        distortion: InputFloat = 0.0,
        detail: InputFloat = 2.0,
        detail_scale: InputFloat = 1.0,
        detail_roughness: InputFloat = 0.5,
        phase_offset: InputFloat = 0.0,
    ) -> "WaveTexture":
        """Create Wave Texture with operation 'Rings'. Use wave texture in rings"""
        return cls(
            wave_type="RINGS",
            vector=vector,
            scale=scale,
            distortion=distortion,
            detail=detail,
            detail_scale=detail_scale,
            detail_roughness=detail_roughness,
            phase_offset=phase_offset,
        )

    @property
    def wave_type(self) -> Literal["BANDS", "RINGS"]:
        return self.node.wave_type

    @wave_type.setter
    def wave_type(self, value: Literal["BANDS", "RINGS"]):
        self.node.wave_type = value

    @property
    def bands_direction(self) -> Literal["X", "Y", "Z", "DIAGONAL"]:
        return self.node.bands_direction

    @bands_direction.setter
    def bands_direction(self, value: Literal["X", "Y", "Z", "DIAGONAL"]):
        self.node.bands_direction = value

    @property
    def rings_direction(self) -> Literal["X", "Y", "Z", "SPHERICAL"]:
        return self.node.rings_direction

    @rings_direction.setter
    def rings_direction(self, value: Literal["X", "Y", "Z", "SPHERICAL"]):
        self.node.rings_direction = value

    @property
    def wave_profile(self) -> Literal["SIN", "SAW", "TRI"]:
        return self.node.wave_profile

    @wave_profile.setter
    def wave_profile(self, value: Literal["SIN", "SAW", "TRI"]):
        self.node.wave_profile = value


